// ─── ConfigRegistry — bridge 設定操作介面的宣告式地基（P0） ─────────────────
//
// 單一 source of truth：一處描述每個「可編輯設定」的路徑、型別、schema、
// 生效策略（hot / restart / syncCommand）、是否敏感。Telegram `/config`（P1）
// 與 Electron 桌面編輯器（P2）都是這份 registry 上面的薄前端——新增設定只改
// 這裡，兩個 UI 自動長出。
//
// 設計刻意「新增讀取入口，不取代啟動載入路徑」：既有的 loadDream /
// loadDomainsConfig / getTopicRules 等載入函式不動（Surgical，避免 scope 膨脹）。
// 見 docs/SPEC-config-ui.md。

import path from "node:path";
import { existsSync, readFileSync } from "node:fs";
import { config, resolveBridgeConfigPath, bridgeConfigWritePath } from "./config.js";
import { detectAgentConfigDir } from "./memory.js";
import { atomicWriteJson, atomicWriteText } from "./atomicJson.js";
import { acpProvidersConfigPath } from "./acp-providers.js";

// ─── 型別 ────────────────────────────────────────────────────────────────────

/** 改後如何生效。 */
export type ReloadStrategy =
  | "hot" // 熱重載，改完即生效（如 topics.json 2s cache）
  | "restart" // 需重啟 bridge 才生效（如 .env）
  | "syncCommand"; // 需跑某個指令才生效（如 /refresh-routing）

/** 值的型別，決定 UI 如何渲染與驗證。 */
export type ConfigType = "enum" | "string" | "boolean" | "number" | "json";

/** 值的來源：.env 環境變數，或某個 JSON 檔。 */
export type ConfigSource = "env" | "json";

/** 結構化表格編輯器的單一欄位（recordSchema 用）。 */
export interface RecordFieldSchema {
  /** 物件內的欄位名（如 "command"）。 */
  key: string;
  label: string;
  /** string=輸入框；enum=下拉；string-list=每行一項；boolean=開關。 */
  type: "string" | "enum" | "string-list" | "boolean";
  options?: string[];
  /** string 欄位的常見值；UI 顯示可自由輸入的 datalist。 */
  suggestions?: string[];
  placeholder?: string;
  /** 選填欄位：值為空時寫入物件時省略。 */
  optional?: boolean;
}

/**
 * 描述一個「Record<字串鍵, 物件>」型 JSON（如 acp-providers.json）的結構，
 * 讓桌面 UI 渲染成每列一筆的表格編輯器而非裸 textarea。純 UI hint——
 * 後端讀寫/驗證仍走既有 json 路徑（type === "json"）。
 */
export interface RecordSchema {
  /** 鍵欄位的標題（如 "識別碼"）。 */
  keyLabel: string;
  fields: RecordFieldSchema[];
}

/** JSON 物件內一個有序物件陣列的桌面 UI schema（如 dream.steps）。 */
export interface ObjectListSchema {
  arrayPath: string;
  itemLabel: string;
  fields: RecordFieldSchema[];
  reorderable?: boolean;
  booleanFields?: Array<{ key: string; label: string; defaultValue: boolean }>;
}

/** 輸入時的即時防呆提示：值含 `contains` 子字串（不分大小寫）時顯示 message。 */
export interface ConfigWarn {
  contains: string;
  message: string;
}

export interface ConfigEntry {
  /** 穩定識別碼，UI/協定用，kebab-case。 */
  key: string;
  /** 人類可讀標題。 */
  label: string;
  /** UI 分組。 */
  group: string;
  source: ConfigSource;
  /**
   * 解析出實際持有這個值的檔案絕對路徑。每個 entry 自己知道怎麼找檔，
   * 因為 topics.json 在 MEMORY_DIR 根、config/*.json 在 MEMORY_DIR/config、
   * .env 在 cwd——不能假設同一個目錄。
   */
  locate: () => string;
  /**
   * 寫入路徑（若與讀取不同）。config/*.json 讀取含舊位置 fallback，但寫入
   * 一律導向 MEMORY_DIR/config（bridgeConfigWritePath）以完成遷移。省略時
   * 寫入路徑 = locate()。
   */
  locateWrite?: () => string;
  /**
   * env source：環境變數名（如 "ACP_MODEL"）。
   * json source：檔案內的 dot-path（如 "chat.model"）；空字串代表整個檔案。
   */
  valuePath: string;
  type: ConfigType;
  /** type === "enum" 時的合法值。 */
  options?: string[];
  reloadStrategy: ReloadStrategy;
  /** reloadStrategy === "syncCommand" 時，提示使用者要跑的指令。 */
  syncCommand?: string;
  /** 是否開放編輯。false 或不在 registry = UI 不顯示（除非 readonly）。 */
  editable: boolean;
  /**
   * 唯讀展示：editable=false 但仍要在 UI 顯示當前值（不給編輯控制項、無儲存鈕）。
   * 用於「只想看、不想改」的狀態（如目前綁定的 agent）。
   */
  readonly?: boolean;
  /** 敏感值（API key / token），readValue 會遮蔽。 */
  sensitive?: boolean;
  /** 一句話說明。 */
  description?: string;
  /**
   * string 型別的建議值清單。UI 渲染成 datalist（下拉建議但仍可自由輸入），
   * 用於 fuzzy alias 這類「有常見值但不能鎖死」的欄位（如 model / 啟動指令）。
   */
  suggestions?: string[];
  /**
   * json 型別且值為 Record<字串鍵, 物件> 時，桌面 UI 據此渲染結構化表格
   * 編輯器（如 acp-providers）。Telegram 端無此渲染，回退成 JSON 整份輸入。
   */
  recordSchema?: RecordSchema;
  /** json 物件內有序陣列的結構化桌面編輯器。 */
  objectListSchema?: ObjectListSchema;
  /** 輸入時即時防呆提示（僅桌面 UI 顯示，不阻擋寫入）。 */
  warn?: ConfigWarn;
}

/** readValue 的結果。 */
export interface ReadResult {
  /** 值是否存在（env 有該行 / json 有該路徑）。 */
  exists: boolean;
  /** 人類可讀的當前值（sensitive 已遮蔽）。 */
  display: string;
  /**
   * 實際值，供編輯 round-trip 用。sensitive 時省略以免外洩。
   * json 整檔時是物件；env 時是字串。
   */
  raw?: unknown;
}

// ─── 路徑 helper ──────────────────────────────────────────────────────────────

/** .env 檔絕對路徑。dotenv 從 cwd 載入，故與 cwd 對齊。 */
export function envFilePath(): string {
  return path.join(process.cwd(), ".env");
}

/** config/ 底下某 json 的讀取路徑（含舊位置 fallback）。 */
function bridgeJson(name: string): string {
  return resolveBridgeConfigPath(name, detectAgentConfigDir());
}

// ─── 不可編輯 / 隱藏清單 ──────────────────────────────────────────────────────
//
// 自動生成檔與 per-chat 狀態檔——不是「使用者設定」，UI 一律不顯示。
// 這裡列檔名（basename 或相對片段）僅供文件化與 UI 過濾參考；registry
// 本身不含這些條目就等於隱藏，此清單是「明確宣告不開放」的雙保險。
export const HIDDEN_CONFIGS: readonly string[] = [
  "agents", // AGENT_CONFIG_DIR/agents/*.json — /specialist create 自動生成
  "specialists.json", // specialist 清單，由指令管理，非手改
  "skill-usage.json", // 技能使用統計，自動累積
  "goal-state", // per-chat /goal 狀態
  "acp-session-registry.json", // ACP session 登記冊，runtime 自動維護
  ".restart-pending.json", // 重啟擱置隊列，bridge 內部用
  "pending-extract.jsonl", // 事實萃取重試隊列
];

