/** 取一個 entry。 */
export function getEntry(key: string): ConfigEntry | undefined {
  return CONFIG_REGISTRY.find((e) => e.key === key);
}

/** 可編輯的條目（寫入 gate 用）。 */
export function editableEntries(): ConfigEntry[] {
  return CONFIG_REGISTRY.filter((e) => e.editable);
}

/**
 * UI 要顯示的條目：可編輯 + 唯讀展示。列表/導航用這個，寫入仍以
 * editable 為準（readonly 條目 POST 會被 writeValue 擋下）。
 */
export function visibleEntries(): ConfigEntry[] {
  return CONFIG_REGISTRY.filter((e) => e.editable || e.readonly);
}

// ─── 讀取層 ───────────────────────────────────────────────────────────────────

const MASK = "••••••";

/**
 * 從 .env 檔（非 process.env，避免編輯後 stale）取一個變數的當前值。
 * 回傳原始字串（去掉包住的引號），找不到回 undefined。
 */
function readEnvValue(filePath: string, key: string): string | undefined {
  if (!existsSync(filePath)) return undefined;
  let raw: string;
  try {
    raw = readFileSync(filePath, "utf8");
  } catch {
    return undefined;
  }
  // 逐行找 `KEY=` 或 `export KEY=`；最後一個定義獲勝（dotenv 語意：先定義獲勝，
  // 但編輯情境下取最後一行較符合直覺——env 檔通常一 key 一行，無重複）。
  const re = new RegExp(`^\\s*(?:export\\s+)?${escapeRegExp(key)}\\s*=(.*)$`);
  let found: string | undefined;
  for (const line of raw.split(/\r?\n/)) {
    if (line.trimStart().startsWith("#")) continue;
    const m = line.match(re);
    if (m) found = m[1];
  }
  if (found === undefined) return undefined;
  return unquoteEnv(found.trim());
}

/** 去掉 env 值兩側成對引號；未加引號則原樣（不處理 inline comment，保守）。 */
function unquoteEnv(v: string): string {
  if (v.length >= 2) {
    const q = v[0];
    if ((q === '"' || q === "'") && v[v.length - 1] === q) {
      return v.slice(1, -1);
    }
  }
  return v;
}

function escapeRegExp(s: string): string {
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

/** 依 dot-path 在物件內取值。空 path 回整個物件。 */
function getByPath(obj: unknown, dotPath: string): { exists: boolean; value: unknown } {
  if (dotPath === "") return { exists: obj !== undefined, value: obj };
  let cur: any = obj;
  for (const seg of dotPath.split(".")) {
    if (cur == null || typeof cur !== "object" || !(seg in cur)) {
      return { exists: false, value: undefined };
    }
    cur = cur[seg];
  }
  return { exists: true, value: cur };
}

/** 讀 JSON 檔並容錯（ENOENT / 壞 JSON 回 undefined，不丟）。 */
function readJsonFileSync(filePath: string): unknown {
  if (!existsSync(filePath)) return undefined;
  try {
    const raw = readFileSync(filePath, "utf8");
    if (raw.trim() === "") return undefined;
    return JSON.parse(raw);
  } catch (err) {
    console.error(`[configRegistry] ${filePath} 非合法 JSON：${(err as Error).message}`);
    return undefined;
  }
}

/** 把任意值轉成人類可讀顯示字串。 */
function toDisplay(value: unknown, type: ConfigType): string {
  if (value === undefined || value === null) return "(未設定)";
  if (type === "json" || typeof value === "object") {
    const s = JSON.stringify(value, null, 2);
    return s.length > 800 ? s.slice(0, 800) + "\n… (截斷)" : s;
  }
  if (value === "") return "(空字串)";
  return String(value);
}

/**
 * 讀一個 entry 的當前值。純同步、無副作用。
 * sensitive 條目回傳遮蔽版且不含 raw。
 */
export function readValue(entry: ConfigEntry): ReadResult {
  if (entry.source === "env") {
    const v = readEnvValue(entry.locate(), entry.valuePath);
    const exists = v !== undefined;
    if (entry.sensitive) {
      return { exists, display: exists ? MASK : "(未設定)" };
    }
    return { exists, display: toDisplay(v, entry.type), raw: v };
  }
  // json
  const obj = readJsonFileSync(entry.locate());
  const { exists, value } = getByPath(obj, entry.valuePath);
  if (entry.sensitive) {
    return { exists, display: exists ? MASK : "(未設定)" };
  }
  return { exists, display: toDisplay(value, entry.type), raw: value };
}

// ─── 驗證層 ───────────────────────────────────────────────────────────────────

export type ValidateResult =
  | { ok: true; value: unknown }
  | { ok: false; error: string };

/**
 * 把使用者輸入的原始字串依 entry.type 驗證並轉型。寫入前必過。
 * - boolean：true/false/1/0/yes/no/on/off/是/否
 * - number：可轉有限數字
 * - enum：必須在 options 內
 * - json：可 JSON.parse
 * - string：原樣
 * 回傳轉型後的值（env 最終仍以字串落地；json 為物件/原值）。
 */
export function validateInput(entry: ConfigEntry, raw: string): ValidateResult {
  const s = raw.trim();
  switch (entry.type) {
    case "boolean": {
      const t = s.toLowerCase();
      if (["true", "1", "yes", "on", "是"].includes(t)) return { ok: true, value: true };
      if (["false", "0", "no", "off", "否"].includes(t)) return { ok: true, value: false };
      return { ok: false, error: `boolean 只接受 true/false（收到 "${s}"）` };
    }
    case "number": {
      const n = Number(s);
      if (!Number.isFinite(n)) return { ok: false, error: `不是有效數字："${s}"` };
      return { ok: true, value: n };
    }
    case "enum": {
      const opts = entry.options ?? [];
      if (!opts.includes(s)) {
        return { ok: false, error: `必須是下列之一：${opts.join(" / ")}` };
      }
      return { ok: true, value: s };
    }
    case "json": {
      try {
        return { ok: true, value: JSON.parse(s) };
      } catch (err) {
        return { ok: false, error: `JSON 解析失敗：${(err as Error).message}` };
      }
    }
    case "string":
    default:
      return { ok: true, value: s };
  }
}

// ─── 寫入層 ───────────────────────────────────────────────────────────────────

/** 依 dot-path 在物件內設值（回傳新物件的同一參照，就地修改）。 */
function setByPath(obj: any, dotPath: string, value: unknown): any {
  const segs = dotPath.split(".");
  let cur = obj;
  for (let i = 0; i < segs.length - 1; i++) {
    const seg = segs[i];
    if (cur[seg] == null || typeof cur[seg] !== "object") cur[seg] = {};
    cur = cur[seg];
  }
  cur[segs[segs.length - 1]] = value;
  return obj;
}

/** env 值格式化：含空白/特殊字元/空字串時加雙引號。 */
function formatEnvValue(value: unknown): string {
  const s = value === null || value === undefined ? "" : String(value);
  if (s === "" || /[\s"'#=]/.test(s)) {
    return `"${s.replace(/"/g, '\\"')}"`;
  }
  return s;
}

/**
 * .env 保序寫入：只替換目標 key 的那一行（保留註解、順序、其餘行）；
 * 不存在則附加到檔尾。原子 tmp+rename。
 */
async function writeEnvValue(filePath: string, key: string, value: unknown): Promise<void> {
  let raw = "";
  if (existsSync(filePath)) {
    raw = readFileSync(filePath, "utf8");
  }
  const newline = raw.includes("\r\n") ? "\r\n" : "\n";
  const lines = raw.split(/\r?\n/);
  const re = new RegExp(`^\\s*(?:export\\s+)?${escapeRegExp(key)}\\s*=`);
  const formatted = `${key}=${formatEnvValue(value)}`;
  let replaced = false;
  for (let i = 0; i < lines.length; i++) {
    if (lines[i].trimStart().startsWith("#")) continue;
    if (re.test(lines[i])) {
      lines[i] = formatted;
      replaced = true;
      // 不 break：若有重複定義（不應發生），最後一個獲勝與 readEnvValue 一致；
      // 但只改最後一個以免留下 stale 定義——這裡改全部以徹底消歧義。
    }
  }
  let body: string;
  if (replaced) {
    body = lines.join(newline);
  } else {
    // 附加：確保與前一行有換行分隔。
    const trimmed = raw.replace(/\s*$/, "");
    body = (trimmed === "" ? "" : trimmed + newline) + formatted + newline;
  }
  await atomicWriteText(filePath, body);
}

/**
 * 寫入一個 entry 的值（value 應已通過 validateInput）。
 * - env：保序寫 .env（值以字串落地）
 * - json 整檔：原子覆寫整個物件
 * - json dot-path：讀取現有整檔 → 就地設值 → 原子覆寫（讀舊位置、寫新位置）
 */
export async function writeValue(entry: ConfigEntry, value: unknown): Promise<void> {
  if (!entry.editable) {
    throw new Error(`設定 "${entry.key}" 不可編輯`);
  }
  const writePath = (entry.locateWrite ?? entry.locate)();
  if (entry.source === "env") {
    await writeEnvValue(writePath, entry.valuePath, value);
    return;
  }
  // json
  if (entry.valuePath === "") {
    await atomicWriteJson(writePath, value);
    return;
  }
  const readPath = entry.locate();
  const current = (readJsonFileSync(readPath) as any) ?? {};
  setByPath(current, entry.valuePath, value);
  await atomicWriteJson(writePath, current);
}

/**
 * 寫入後依生效策略回傳給使用者的提示。UI 用來決定是否跳重啟確認。
 */
export function effectHint(entry: ConfigEntry): { needsRestart: boolean; message: string } {
  switch (entry.reloadStrategy) {
    case "hot":
      return { needsRestart: false, message: "✅ 已生效（熱重載，無需重啟）。" };
    case "syncCommand":
      return {
        needsRestart: false,
        message: `✅ 已寫入。請執行 ${entry.syncCommand ?? "對應同步指令"} 使其生效。`,
      };
    case "restart":
    default:
      return { needsRestart: true, message: "⚠️ 已寫入，需重啟 bridge 才生效。" };
  }
}

