/**
 * ACP backend definition table for /agent hot-swap (SPEC-acp-hot-swap).
 *
 * Backends live in ${MEMORY_DIR}/config/acp-providers.json so each machine
 * keeps its own command lines (npx package forms, local shims, …):
 *
 *   {
 *     "kiro":   { "command": "kiro-cli acp", "label": "Kiro CLI" },
 *     "claude": { "command": "npx claude-agent-acp", "label": "Claude Code",
 *                 "model": "claude-fable-5", "effort": "high" },
 *     "codex":  { "command": "npx @zed-industries/codex-acp", "label": "Codex" }
 *   }
 *
 * `model` / `effort` are per-backend pins. Codex receives them as CLI
 * `-c model=...` / `-c model_reasoning_effort=...`; Kiro receives model as
 * CLI `--model ...` and ignores effort; Claude ACP adapters receive both via
 * session/set_config_option after session/new. When the file is missing or
 * empty the table degrades to a single "default" entry mirroring the .env
 * agent, so /agent stays functional without configuration.
 */
import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { bridgeConfigWritePath, config, resolveBridgeConfigPath } from "./config.js";
import { detectAgentConfigDir } from "./memory.js";
import { applyModelEffortToCommand } from "./acp-adapter-config.js";

export interface AcpBackendDef {
  /** Table key — what the user types after /agent. */
  key: string;
  command: string;
  args: string[];
  label: string;
  /** Optional per-backend model pin. Adapter-specific handling happens at parse time. */
  model?: string;
  /** Optional per-backend reasoning-effort pin ("low"/"medium"/"high"). */
  effort?: string;
}

export const DEFAULT_BACKEND_KEY = "default";

interface RawEntry {
  command?: string;
  label?: string;
  model?: string;
  effort?: string;
}

/**
 * Pure parser — no disk / env access so smoke scripts can exercise it.
 * Entries without a usable command string are skipped. `agentName` replays
 * buildAgent()'s ACP_AGENT_NAME → `--agent <name>` append for kiro commands
 * (the only CLI that takes --agent), so table entries don't lose it.
 */
export function parseAcpProviders(
  raw: string,
  agentName?: string,
): Record<string, AcpBackendDef> {
  const json = JSON.parse(raw) as Record<string, RawEntry>;
  const out: Record<string, AcpBackendDef> = {};
  for (const [key, entry] of Object.entries(json)) {
    if (!entry || typeof entry.command !== "string" || entry.command.trim() === "") continue;
    const parts = entry.command.trim().split(/\s+/);
    const command = parts[0];
    const args = parts.slice(1);
    if (agentName && command.toLowerCase().includes("kiro") && !args.includes("--agent")) {
      args.push("--agent", agentName);
    }
    const resolved = applyModelEffortToCommand(
      command,
      args,
      entry.model,
      entry.effort,
    );
    out[key] = {
      key,
      command: resolved.command,
      args: resolved.args,
      label: entry.label?.trim() || key,
      model: resolved.acpModel,
      effort: resolved.acpEffort,
    };
  }
  return out;
}

/** Fallback table when acp-providers.json is missing/empty: the .env agent. */
export function defaultBackends(): Record<string, AcpBackendDef> {
  const resolved = applyModelEffortToCommand(
    config.agent.command,
    config.agent.args,
    config.acpModel,
    config.acpEffort,
  );
  return {
    [DEFAULT_BACKEND_KEY]: {
      key: DEFAULT_BACKEND_KEY,
      command: resolved.command,
      args: [...resolved.args],
      label: `${resolved.command}（.env 預設）`,
      model: resolved.acpModel,
      effort: resolved.acpEffort,
    },
  };
}

/** Resolved read path (MEMORY_DIR/config first, AGENT_CONFIG_DIR fallback). */
export function acpProvidersConfigPath(): string {
  return resolveBridgeConfigPath("acp-providers.json", detectAgentConfigDir());
}

/** Seed 範本裡的單一 entry（與 RawEntry 同形，export 供 smoke script 斷言）。 */
export interface SeedEntry {
  command: string;
  label: string;
  model?: string;
  effort?: string;
}

/** /agent init 的已知 backend scaffold（command 為常見形式，不保證本機可用）。 */
const KNOWN_BACKENDS: Array<{ key: string; match: RegExp; command: string; label: string }> = [
  { key: "kiro", match: /kiro/i, command: "kiro-cli acp", label: "Kiro CLI" },
  { key: "claude", match: /claude/i, command: "npx claude-agent-acp", label: "Claude Code" },
  { key: "codex", match: /codex/i, command: "npx @zed-industries/codex-acp", label: "Codex" },
];

/**
 * Pure template builder for `/agent init` — no disk / env access so smoke
 * scripts can exercise it. The current .env agent becomes the one guaranteed-
 * valid entry (key inferred from its command line); the other known backends
 * are included as scaffolds whose labels flag that the command needs review.
 */
export function buildSeedTemplate(
  envCommand: string,
  envArgs: string[],
  model?: string,
  effort?: string,
): Record<string, SeedEntry> {
  const envFull = [envCommand, ...envArgs].join(" ").trim();
  const matched = KNOWN_BACKENDS.find((b) => b.match.test(envFull));
  const envKey = matched?.key ?? DEFAULT_BACKEND_KEY;
  const out: Record<string, SeedEntry> = {
    [envKey]: {
      command: envFull,
      label: `${matched?.label ?? envKey}（.env 當前 agent）`,
      model: model || undefined,
      effort: effort || undefined,
    },
  };
  for (const b of KNOWN_BACKENDS) {
    if (b.key === envKey) continue;
    out[b.key] = { command: b.command, label: `${b.label}（scaffold，請確認 command）` };
  }
  return out;
}

/**
 * Write the seed template to the primary config location. Never overwrites:
 * if the file already exists (primary or AGENT_CONFIG_DIR fallback) it
 * returns `created: false` with that path.
 */
export function seedAcpProvidersFile(): { path: string; created: boolean } {
  const existing = acpProvidersConfigPath();
  if (existsSync(existing)) return { path: existing, created: false };
  const target = bridgeConfigWritePath("acp-providers.json");
  const template = buildSeedTemplate(
    config.agent.command,
    config.agent.args,
    config.acpModel || undefined,
    config.acpEffort || undefined,
  );
  writeFileSync(target, JSON.stringify(template, null, 2) + "\n", "utf8");
  return { path: target, created: true };
}

export function loadAcpProviders(): Record<string, AcpBackendDef> {
  try {
    const raw = readFileSync(acpProvidersConfigPath(), "utf8");
    const parsed = parseAcpProviders(
      raw,
      (process.env.ACP_AGENT_NAME ?? "").trim() || undefined,
    );
    if (Object.keys(parsed).length > 0) return parsed;
  } catch {
    /* missing or unparseable — degrade to the .env agent */
  }
  return defaultBackends();
}

